// Flujo de prueba E2E completo

// PASO 1: Crear productos (puerto 8082)
POST http://localhost:8082/product
{"name": "Cuenta Corriente", "price": 0.0}
// ID: 1

POST http://localhost:8082/product
{"name": "Cuenta Ahorros", "price": 0.0}
// ID: 2

// PASO 2: Crear customer con productos (puerto 8081)
POST http://localhost:8081/customer
{
  "name": "Carlos Ruiz",
  "phoneNumber": "555-9999",
  "productIds": [1, 2]
}
// ID: 1

// PASO 3: Crear transacción válida (puerto 8083)
POST http://localhost:8083/transaction
{
  "customerId": 1,
  "productId": 1,
  "amount": 1000.0
}
// Respuesta: {"id": 1, "status": "COMPLETED", ...}

// PASO 4: Intentar transacción inválida
POST http://localhost:8083/transaction
{
  "customerId": 1,
  "productId": 3, // Customer no tiene producto 3
  "amount": 500.0
}
// Error: "Customer no posee este producto"

// PASO 5: Consultar transaction con detalles
GET http://localhost:8083/transaction/1
// Respuesta con datos agregados:
{
  "id": 1,
  "amount": 1000.0,
  "status": "COMPLETED",
  "customer": {
    "id": 1,
    "name": "Carlos Ruiz",
    "phoneNumber": "555-9999"
  },
  "product": {
    "id": 1,
    "name": "Cuenta Corriente",
    "price": 0.0
  }
}
